function parseCard(ref){return{base:ref.replace(/\+$/,''),upgraded:ref.endsWith('+')}}
function cardRarity(ref){const id=parseCard(ref).base;return cardRaritySets.rare.has(id)?'rare':cardRaritySets.uncommon.has(id)?'uncommon':'common'}
function cardVisual(ref){const id=parseCard(ref).base,index=Math.max(0,Object.keys(cards).indexOf(id)),card=cards[id],marks={broadside:'☄',cannon:'✹',harpoon:'⌁',torpedo:'◉',lightning:'ϟ',ram:'◆',flare:'✦'},mark=marks[card.weapon]||cardSchools[card.school].mark;return{code:String(index+1).padStart(2,'0'),mark,hue:(index%7-3)*9,x:30+(index*17)%51,y:25+(index*23)%51,scale:1.04+(index%5)*.035}}
function rollCardRewards(count=3,elite=false){const pool=Object.keys(cards).filter(id=>!['cut','brace'].includes(id)),chosen=[];while(chosen.length<count&&pool.length){const weights=pool.map(id=>{const rarity=cardRarity(id);return rarity==='rare'?(elite?20:10):rarity==='uncommon'?32:58}),total=weights.reduce((sum,value)=>sum+value,0);let roll=Math.random()*total,index=0;for(;index<pool.length-1&&roll>=weights[index];index++)roll-=weights[index];chosen.push(pool.splice(index,1)[0])}return chosen}
function describeCard(card){const parts=[],hits=card.hits||1;if(card.damage)parts.push(hits>1?`造成 ${card.damage} 点伤害 ${hits} 次。`:`造成 ${card.damage} 点伤害。`);if(card.blockFromCurrent)parts.push(`追加当前护甲 ${Math.round(card.blockFromCurrent*100)}% 的伤害。`);if(card.rustScale)parts.push(`目标每层锈蚀额外造成 ${card.rustScale} 点。`);if(card.consumeRust)parts.push(`消耗锈蚀，每层额外造成 ${card.consumeRust} 点。`);if(card.splash)parts.push(`对其他敌舰造成 ${Math.round(card.splash*100)}% 伤害。`);if(card.splashRust)parts.push(`对其他敌舰施加 ${card.splashRust} 层锈蚀。`);if(card.vulnerable)parts.push(`施加 ${card.vulnerable} 层锈蚀。`);if(card.block)parts.push(`获得 ${card.block} 点护甲。`);if(card.firepower)parts.push(`本回合火力 +${card.firepower}。`);if(card.counter)parts.push(`本回合反击 ${card.counter}。`);if(card.heal)parts.push(`恢复 ${card.heal} 点生命。`);if(card.energy)parts.push(`获得 ${card.energy} 点潮力。`);if(card.draw)parts.push(`抽 ${card.draw} 张牌。`);if(card.comboNeed){const effects=[];if(card.comboDamage)effects.push(`额外造成 ${card.comboDamage} 点`);if(card.comboBlock)effects.push(`额外获得 ${card.comboBlock} 点护甲`);if(card.comboHits)effects.push(`额外攻击 ${card.comboHits} 次`);if(card.drawIfCombo)effects.push(`额外抽 ${card.drawIfCombo} 张牌`);if(card.energyIfCombo)effects.push(`获得 ${card.energyIfCombo} 点潮力`);if(effects.length)parts.push(`连潮 ${card.comboNeed}：${effects.join('，')}。`)}return parts.join('')}
function getCard(ref){const {base,upgraded}=parseCard(ref),original=cards[base];if(!upgraded)return original;const card={...original,name:`${original.name}+`};if(card.damage)card.damage+=card.hits>1?1:3;if(card.block)card.block+=3;if(card.heal)card.heal+=1;if(card.vulnerable)card.vulnerable+=1;if(card.firepower)card.firepower+=1;if(card.counter)card.counter+=2;if(card.rustScale)card.rustScale+=1;if(card.consumeRust)card.consumeRust+=1;if(card.comboDamage)card.comboDamage+=3;if(card.comboBlock)card.comboBlock+=3;card.text=describeCard(card);return card}
function cardRuleHelp(card){const keys=[];if(card.vulnerable||card.rustScale||card.consumeRust||card.splashRust)keys.push('rust');if(card.block||card.blockFromCurrent)keys.push('block');if(card.energy||card.energyIfCombo)keys.push('energy');if(card.draw||card.drawIfCombo)keys.push('draw');if(card.comboNeed)keys.push('combo');if(card.firepower)keys.push('firepower');if(card.counter)keys.push('counter');return[...new Set(keys)].map(key=>`${combatTerms[key].name}：${combatTerms[key].text}`).join('\n')}
